import{_ as s,o as e,c as n,ak as t}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"CAS 单点登录原理与流程","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/scenario/unified-auth/cas-sso.md","filePath":"distributed/scenario/unified-auth/cas-sso.md","lastUpdated":1774318215000}'),i={name:"distributed/scenario/unified-auth/cas-sso.md"};function r(l,a,d,p,h,c){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="cas-单点登录原理与流程" tabindex="-1">CAS 单点登录原理与流程 <a class="header-anchor" href="#cas-单点登录原理与流程" aria-label="Permalink to “CAS 单点登录原理与流程”">​</a></h1><p>你在 A 网站登录了，打开 B 网站，发现——咦，已经登录了？</p><p>这听起来很自然，但你有没有想过：<strong>A 网站是怎么「告诉」B 网站用户已经登录的？</strong></p><p>这就是 SSO（Single Sign-On，单点登录）要解决的问题。</p><h2 id="sso-的定义" tabindex="-1">SSO 的定义 <a class="header-anchor" href="#sso-的定义" aria-label="Permalink to “SSO 的定义”">​</a></h2><p>单点登录的核心思想很简单：<strong>一次登录，多处访问。</strong></p><p>用户在一个系统登录后，访问其他相关系统，无需再次输入用户名密码。这不仅提升了用户体验，更重要的是——<strong>减少了用户在不同系统使用不同密码带来的安全风险。</strong></p><h2 id="cas-的核心流程" tabindex="-1">CAS 的核心流程 <a class="header-anchor" href="#cas-的核心流程" aria-label="Permalink to “CAS 的核心流程”">​</a></h2><p>CAS（Central Authentication Service，中心认证服务）是 SSO 最经典的实现方案。它的工作流程可以用一句话概括：<strong>「认证中心」统一验证，「各个系统」验证票据。</strong></p><h3 id="第一步-用户访问-a-系统-未登录" tabindex="-1">第一步：用户访问 A 系统，未登录 <a class="header-anchor" href="#第一步-用户访问-a-系统-未登录" aria-label="Permalink to “第一步：用户访问 A 系统，未登录”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户 → 访问 A 系统 /home</span></span>
<span class="line"><span>A 系统检查 Session → 发现未登录</span></span>
<span class="line"><span>A 系统 → 重定向到 CAS Server，带着 service 参数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>A 系统告诉 CAS：「有个用户想访问我，你先帮我验证一下。」</p><h3 id="第二步-cas-server-验证用户-创建-tgc" tabindex="-1">第二步：CAS Server 验证用户，创建 TGC <a class="header-anchor" href="#第二步-cas-server-验证用户-创建-tgc" aria-label="Permalink to “第二步：CAS Server 验证用户，创建 TGC”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CAS Server → 显示登录页面</span></span>
<span class="line"><span>用户输入用户名、密码 → CAS Server 验证</span></span>
<span class="line"><span>验证通过 → 创建 TGT（Ticket Granting Ticket）和 TGC（Cookie）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>TGT 是 CAS 服务端存储的用户票据，TGC 是浏览器 Cookie。两者配合，让 CAS 记住「这个浏览器已经登录过了」。</p><h3 id="第三步-用户带着-st-回到-a-系统" tabindex="-1">第三步：用户带着 ST 回到 A 系统 <a class="header-anchor" href="#第三步-用户带着-st-回到-a-系统" aria-label="Permalink to “第三步：用户带着 ST 回到 A 系统”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CAS Server → 生成 ST（Service Ticket）</span></span>
<span class="line"><span>重定向回 A 系统，带着 ST 参数</span></span>
<span class="line"><span>A 系统收到 ST → 校验 ST 有效性（CAS Server 返回）</span></span>
<span class="line"><span>验证通过 → 创建 A 系统的 Session，用户成功登录</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ST（Service Ticket）是一次性的，用完即废。它的存在时间很短，通常是一次 HTTP 请求的时间。</p><h3 id="第四步-用户访问-b-系统" tabindex="-1">第四步：用户访问 B 系统 <a class="header-anchor" href="#第四步-用户访问-b-系统" aria-label="Permalink to “第四步：用户访问 B 系统”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户 → 访问 B 系统 /order</span></span>
<span class="line"><span>B 系统检查 Session → 发现未登录</span></span>
<span class="line"><span>B 系统 → 重定向到 CAS Server，带着 service 参数</span></span>
<span class="line"><span>CAS Server → 发现浏览器已有 TGC → 直接生成 ST</span></span>
<span class="line"><span>重定向回 B 系统，带着 ST 参数</span></span>
<span class="line"><span>B 系统验证 ST → 登录成功</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>注意第四步的关键差异：<strong>用户不需要重新输入密码</strong>，因为 CAS 已经通过 TGC 认识了这个浏览器。</p><h2 id="cas-的三个核心票据" tabindex="-1">CAS 的三个核心票据 <a class="header-anchor" href="#cas-的三个核心票据" aria-label="Permalink to “CAS 的三个核心票据”">​</a></h2><p>理解 CAS，必须理解这三个票据的关系：</p><table tabindex="0"><thead><tr><th>票据</th><th>全称</th><th>存储位置</th><th>用途</th></tr></thead><tbody><tr><td>TGC</td><td>Ticket Granting Cookie</td><td>浏览器 Cookie</td><td>标识用户的登录状态</td></tr><tr><td>TGT</td><td>Ticket Granting Ticket</td><td>CAS Server 内存/Redis</td><td>生成 ST 的凭证</td></tr><tr><td>ST</td><td>Service Ticket</td><td>无（一次性）</td><td>各系统验证用户身份</td></tr></tbody></table><p>TGT 和 TGC 的关系是：TGC 是 TGT 的「钥匙」，浏览器带着 TGC 访问 CAS，CAS 用 TGC 换取 TGT，再用 TGT 生成 ST。</p><h2 id="cas-的优点" tabindex="-1">CAS 的优点 <a class="header-anchor" href="#cas-的优点" aria-label="Permalink to “CAS 的优点”">​</a></h2><p><strong>成熟开源</strong>：CAS 是 Yale 大学发起的一套开源项目，社区活跃，文档完善。</p><p><strong>支持代理模式</strong>：CAS 支持代理认证，一个系统可以代替用户去访问另一个系统的资源。想象一下：你的邮件系统代理用户去访问日历系统获取日程。</p><p><strong>安全性高</strong>：ST 一次性使用，即使被截获也无法重复利用。</p><p><strong>多协议支持</strong>：除了 CAS 协议，还支持 OAuth2、SAML 等协议。</p><h2 id="cas-vs-oauth2" tabindex="-1">CAS vs OAuth2 <a class="header-anchor" href="#cas-vs-oauth2" aria-label="Permalink to “CAS vs OAuth2”">​</a></h2><p>很多人容易混淆 CAS 和 OAuth2，它们的定位不同：</p><table tabindex="0"><thead><tr><th>对比</th><th>CAS</th><th>OAuth2</th></tr></thead><tbody><tr><td>定位</td><td>企业内网单点登录</td><td>开放平台授权</td></tr><tr><td>关注点</td><td>认证（你是谁）</td><td>授权（你能访问什么）</td></tr><tr><td>Token</td><td>ST（一次性）</td><td>Access Token（可刷新）</td></tr><tr><td>复杂度</td><td>相对简单</td><td>灵活但复杂</td></tr><tr><td>适用场景</td><td>企业内部多系统</td><td>第三方应用授权</td></tr></tbody></table><p>简单来说：<strong>CAS 解决的是「用户登录多个系统」的问题，OAuth2 解决的是「第三方应用访问用户数据」的问题。</strong></p><p>两者解决的问题不同，不要混用。</p><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>CAS 的 ST 为什么设计成一次性的？（答：防止 ST 被截获后冒用）</li><li>CAS 如何实现登出？（答：销毁 TGT，各系统收到通知后清除 Session）</li><li>CAS 如何支持多域名？（答：通过 TGC 跨域，各系统配置信任域）</li><li>CAS 的性能瓶颈在哪？（答：每次验证都需要 CAS Server 网络通信）</li></ul><p>如果你对 OAuth2 在微服务中的使用感兴趣，可以继续阅读 <a href="/distributed/scenario/unified-auth/oauth2-microservice">OAuth 2.0 在微服务中的使用</a>。</p><p>一次登录，多处访问——这听起来简单，背后是精心设计的票据机制在支撑。</p>`,39)])])}const S=s(i,[["render",r]]);export{b as __pageData,S as default};
